import { useState, useContext } from "react";
import axios from "axios";
import { AuthContext } from "../context/AuthContext";
import StudyRoom from "../components/StudyRoom"; 

const Dashboard = () => {
    const { token } = useContext(AuthContext);
    const [syllabus, setSyllabus] = useState("");
    const [examDate, setExamDate] = useState("");
    const [tasks, setTasks] = useState([]);

    const handleCreatePlan = async () => {
        try {
            const res = await axios.post("http://localhost:5000/api/plan/create", 
                { syllabus, examDate },
                { headers: { Authorization: `Bearer ${token}` } }
            );
            alert("AI has generated your timetable!");
            fetchTasks();
        } catch (err) {
            console.error(err);
        }
    };

    const fetchTasks = async () => {
        const res = await axios.get("http://localhost:5000/api/tasks", {
            headers: { Authorization: `Bearer ${token}` }
        });
        setTasks(res.data);
    };

    return (
        <div className="p-10">
            <h1>Welcome to StudyPulse</h1>
            <div className="flex flex-col gap-4 w-1/2">
                <textarea 
                    placeholder="Paste your syllabus here (comma separated topics)..."
                    onChange={(e) => setSyllabus(e.target.value)}
                    className="border p-2"
                />
                <input 
                    type="date" 
                    onChange={(e) => setExamDate(e.target.value)}
                    className="border p-2"
                />
                <button onClick={handleCreatePlan} className="bg-blue-500 text-white p-2">
                    Generate AI Schedule
                </button>
            </div>

            <div className="mt-10">
                <h2>Your Schedule</h2>
                {tasks.map(task => (
                    <div key={task._id} className="border p-2 my-2 flex justify-between">
                        <span>{task.title} - {new Date(task.date).toDateString()}</span>
                        <button className="bg-green-500 text-white p-1">Start Studying</button>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default Dashboard;
